// 树状数组模板（单点更新，区间查询）
class FenwickTree {
    vector<int> bit;
    int n;
public:
    FenwickTree(int size) : n(size), bit(size + 1, 0) {}

    void update(int idx, int delta) {
        for (; idx <= n; idx += idx & -idx)
            bit[idx] += delta;
    }

    int query(int idx) {
        int sum = 0;
        for (; idx > 0; idx -= idx & -idx)
            sum += bit[idx];
        return sum;
    }

    int rangeQuery(int l, int r) {
        return query(r) - query(l - 1);
    }
};

// 线段树模板（区间更新，区间查询）
class SegmentTree {
    vector<int> tree, lazy;
    int n;

    void pushDown(int node, int left, int right) {
        if (lazy[node] != 0) {
            tree[node] += (right - left + 1) * lazy[node];
            if (left != right) {
                lazy[node * 2] += lazy[node];
                lazy[node * 2 + 1] += lazy[node];
            }
            lazy[node] = 0;
        }
    }

    void updateRange(int node, int left, int right, int l, int r, int val) {
        pushDown(node, left, right);
        if (l > right || r < left) return;
        if (l <= left && right <= r) {
            lazy[node] += val;
            pushDown(node, left, right);
            return;
        }
        int mid = (left + right) / 2;
        updateRange(node * 2, left, mid, l, r, val);
        updateRange(node * 2 + 1, mid + 1, right, l, r, val);
        tree[node] = tree[node * 2] + tree[node * 2 + 1];
    }

    int queryRange(int node, int left, int right, int l, int r) {
        pushDown(node, left, right);
        if (l > right || r < left) return 0;
        if (l <= left && right <= r) return tree[node];
        int mid = (left + right) / 2;
        return queryRange(node * 2, left, mid, l, r) + 
               queryRange(node * 2 + 1, mid + 1, right, l, r);
    }

public:
    SegmentTree(int size) : n(size) {
        tree.resize(4 * size);
        lazy.resize(4 * size);
    }

    void update(int l, int r, int val) {
        updateRange(1, 1, n, l, r, val);
    }

    int query(int l, int r) {
        return queryRange(1, 1, n, l, r);
    }
};

