// 小顶堆（默认）
priority_queue<int, vector<int>, greater<int>> minHeap;
// 大顶堆
priority_queue<int> maxHeap;

// 自定义比较函数
struct Node {
    int val, idx;
    bool operator<(const Node& other) const {
        // 大顶堆：按val从大到小
        return val < other.val;
        // 小顶堆：return val > other.val;
    }
};
priority_queue<Node> pq;

// TopK问题模板
vector<int> topK(vector<int>& nums, int k) {
    priority_queue<int, vector<int>, greater<int>> minHeap;
    for (int num : nums) {
        minHeap.push(num);
        if (minHeap.size() > k) {
            minHeap.pop(); // 移除最小的，保留最大的k个
        }
    }

    vector<int> res;
    while (!minHeap.empty()) {
        res.push_back(minHeap.top());
        minHeap.pop();
    }
    reverse(res.begin(), res.end()); // 从大到小排序
    return res;
}

// 合并K个有序序列
vector<int> mergeKSorted(vector<vector<int>>& arrays) {
    struct Element {
        int val, arrIdx, elemIdx;
        bool operator>(const Element& other) const {
            return val > other.val; // 小顶堆
        }
    };

    priority_queue<Element, vector<Element>, greater<Element>> pq;
    vector<int> result;

    // 初始化：每个数组的第一个元素
    for (int i = 0; i < arrays.size(); i++) {
        if (!arrays[i].empty()) {
            pq.push({arrays[i][0], i, 0});
        }
    }

    while (!pq.empty()) {
        auto [val, arrIdx, elemIdx] = pq.top();
        pq.pop();
        result.push_back(val);

        // 如果当前数组还有下一个元素
        if (elemIdx + 1 < arrays[arrIdx].size()) {
            pq.push({arrays[arrIdx][elemIdx + 1], arrIdx, elemIdx + 1});
        }
    }

    return result;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // 示例：TopK
    vector<int> nums = {3, 2, 1, 5, 6, 4};
    int k = 3;
    vector<int> top3 = topK(nums, k);
    // 输出: 6 5 4

    // 示例：合并有序序列
    vector<vector<int>> arrays = {{1, 4, 7}, {2, 5, 8}, {3, 6, 9}};
    vector<int> merged = mergeKSorted(arrays);
    // 输出: 1 2 3 4 5 6 7 8 9

