}

// Treap 实现（基于旋转）
struct Node {
    int key, priority, size;
    Node *left, *right;
    Node(int k) : key(k), priority(rand()), size(1), left(nullptr), right(nullptr) {}
};

int getSize(Node* node) {
    return node ? node->size : 0;
}

void updateSize(Node* node) {
    if (node) node->size = 1 + getSize(node->left) + getSize(node->right);
}

// 右旋
Node* rotateRight(Node* y) {
    Node* x = y->left;
    Node* T2 = x->right;
    x->right = y;
    y->left = T2;
    updateSize(y);
    updateSize(x);
    return x;
}

// 左旋
Node* rotateLeft(Node* x) {
    Node* y = x->right;
    Node* T2 = y->left;
    y->left = x;
    x->right = T2;
    updateSize(x);
    updateSize(y);
    return y;
}

// 插入
Node* insert(Node* root, int key) {
    if (!root) return new Node(key);
    if (key < root->key) {
        root->left = insert(root->left, key);
        if (root->left->priority > root->priority)
            root = rotateRight(root);
    } else {
        root->right = insert(root->right, key);
        if (root->right->priority > root->priority)
            root = rotateLeft(root);
    }
    updateSize(root);
    return root;
}

// 删除
Node* erase(Node* root, int key) {
    if (!root) return nullptr;
    if (key < root->key) {
        root->left = erase(root->left, key);
    } else if (key > root->key) {
        root->right = erase(root->right, key);
    } else {
        if (!root->left || !root->right) {
            Node* temp = root->left ? root->left : root->right;
            delete root;
            root = temp;
        } else if (root->left->priority > root->right->priority) {
            root = rotateRight(root);
            root->right = erase(root->right, key);
        } else {
            root = rotateLeft(root);
            root->left = erase(root->left, key);
        }
    }
    updateSize(root);
    return root;
}

// 查询第k小（0-indexed）
int kth(Node* root, int k) {
    int leftSize = getSize(root->left);
    if (k < leftSize) return kth(root->left, k);
    if (k == leftSize) return root->key;
    return kth(root->right, k - leftSize - 1);
}

// 查询排名（小于key的元素个数）
int rank(Node* root, int key) {
    if (!root) return 0;
    if (key <= root->key) return rank(root->left, key);
    return 1 + getSize(root->left) + rank(root->right, key);
}

// 字典树节点定义
struct TrieNode {
    TrieNode* children[26]; // 小写字母，可扩展
    int cnt; // 经过该节点的字符串数量
    bool isEnd; // 是否为某个字符串的结尾
    TrieNode() {
        for (int i = 0; i < 26; i++) children[i] = nullptr;
        cnt = 0;
        isEnd = false;
    }
};

class Trie {
private:
    TrieNode* root;
public:
    Trie() {
        root = new TrieNode();
    }

    // 插入字符串
    void insert(string word) {
        TrieNode* node = root;
        for (char c : word) {
            int idx = c - 'a';
            if (!node->children[idx]) {
                node->children[idx] = new TrieNode();
            }
            node = node->children[idx];
            node->cnt++;
        }
        node->isEnd = true;
    }

    // 查询字符串是否存在
    bool search(string word) {
        TrieNode* node = root;
        for (char c : word) {
            int idx = c - 'a';
            if (!node->children[idx]) return false;
            node = node->children[idx];
        }
        return node->isEnd;
    }

    // 查询前缀是否存在
    bool startsWith(string prefix) {
        TrieNode* node = root;
        for (char c : prefix) {
            int idx = c - 'a';
            if (!node->children[idx]) return false;
            node = node->children[idx];
        }
        return true;
    }

    // 统计以prefix为前缀的字符串数量
    int countPrefix(string prefix) {
        TrieNode* node = root;
        for (char c : prefix) {
            int idx = c - 'a';
            if (!node->children[idx]) return 0;
            node = node->children[idx];
        }
        return node->cnt;
    }

    // 01字典树：用于异或最值问题
    struct BinaryTrieNode {
        BinaryTrieNode* children[2];
        int cnt;
        BinaryTrieNode() {
            children[0] = children[1] = nullptr;
            cnt = 0;
        }
    };

    // 插入数字（二进制位从高位到低位）
    void insertBinary(int num, int maxBits = 30) {
        BinaryTrieNode* node = rootBinary;
        for (int i = maxBits; i >= 0; i--) {
            int bit = (num >> i) & 1;
            if (!node->children[bit]) {
                node->children[bit] = new BinaryTrieNode();
            }
            node = node->children[bit];
            node->cnt++;
        }
    }

    // 查询与num异或的最大值
    int queryMaxXor(int num, int maxBits = 30) {
        BinaryTrieNode* node = rootBinary;
        int res = 0;
        for (int i = maxBits; i >= 0; i--) {
            int bit = (num >> i) & 1;
            // 优先选择相反的位
            if (node->children[bit ^ 1]) {
                res |= (1 << i);
                node = node->children[bit ^ 1];
            } else {
                node = node->children[bit];
            }
        }
        return res;
    }
};

#include <bits/stdc++.h>
using namespace std;

const int MAXN = 1e5 + 5;
const int LOG = 20; // log2(MAXN)

int a[MAXN];
int st[MAXN][LOG]; // st[i][j] 表示区间 [i, i+2^j-1] 的最值
int log2_pre[MAXN]; // 预处理log2值

// 预处理log2值，加速查询
void preprocess_log2(int n) {
    log2_pre[1] = 0;
    for (int i = 2; i <= n; i++) {
        log2_pre[i] = log2_pre[i / 2] + 1;
    }
}

// 构建ST表，O(nlogn)
void build_st(int n) {
    // 初始化长度为1的区间
    for (int i = 1; i <= n; i++) {
        st[i][0] = a[i];
    }

    // 递推计算更长的区间
    for (int j = 1; j < LOG; j++) {
        for (int i = 1; i + (1 << j) - 1 <= n; i++) {
            // 合并两个长度为2^(j-1)的区间
            st[i][j] = max(st[i][j-1], st[i + (1 << (j-1))][j-1]);
            // 如果是求最小值，改为min即可
        }
    }
}

// 查询区间[l, r]的最大值，O(1)
int query_max(int l, int r) {
    int k = log2_pre[r - l + 1];
    // 两个长度为2^k的区间覆盖[l, r]
    return max(st[l][k], st[r - (1 << k) + 1][k]);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, q;
    cin >> n >> q;

    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }

    preprocess_log2(n);
    build_st(n);

    while (q--) {
        int l, r;
        cin >> l >> r;
        cout << query_max(l, r) << "\n";
    }

    return 0;
}
